import anthropic

client = anthropic.Anthropic()

response = client.messages.create(
    model='claude-opus-4-6',
    max_tokens=16000,
    thinking={
        'type': 'enabled',
        'budget_tokens': 10000  # max tokens for internal reasoning
    },
    messages=[{'role': 'user', 'content': 'What is 17 * 23 + 14^2?'}]
)

# Iterate through all content blocks
for block in response.content:
    if block.type == 'thinking':
        print(f"[THINKING BLOCK]\n{block.thinking[:300]}...")
    elif block.type == 'text':
        print(f"[RESPONSE]\n{block.text}")
    elif block.type == 'redacted_thinking':
        # Some thinking may be redacted for safety reasons
        # Always preserve these blocks in multi-turn conversations
        print(f"[REDACTED THINKING - must preserve in history]")

# Streaming with thinking blocks — handling different block types
with client.messages.stream(
    model='claude-opus-4-8',
    max_tokens=16000,
    thinking={'type': 'adaptive', 'display': 'summarized'},
    output_config={'effort': 'high'},
    messages=[{'role': 'user', 'content': 'Explain Fourier transforms intuitively.'}]
) as stream:
    current_block_type = None

    for event in stream:
        if not hasattr(event, 'type'):
            continue

        if event.type == 'content_block_start':
            block = event.content_block
            current_block_type = block.type
            if block.type == 'thinking_summary':
                print("\n--- Thinking Summary ---")
            elif block.type == 'text':
                print("\n--- Response ---")

        elif event.type == 'content_block_delta':
            delta = event.delta
            if current_block_type == 'thinking_summary' and hasattr(delta, 'text'):
                print(delta.text, end='', flush=True)
            elif current_block_type == 'text' and hasattr(delta, 'text'):
                print(delta.text, end='', flush=True)

print("\n--- Stream Complete ---")

tools = [
    {
        'name': 'search_codebase',
        'description': 'Search for code patterns in the repository',
        'input_schema': {
            'type': 'object',
            'properties': {
                'pattern': {'type': 'string', 'description': 'Regex pattern to search for'},
                'file_type': {'type': 'string', 'description': 'File extension to search (e.g. .py, .ts)'}
            },
            'required': ['pattern']
        }
    }
]

# Thinking before first tool call
response = client.messages.create(
    model='claude-opus-4-6',
    max_tokens=16000,
    thinking={'type': 'enabled', 'budget_tokens': 8000},
    tools=tools,
    messages=[{'role': 'user', 'content': 'Find all places where we handle authentication errors.'}]
)

# Response may contain: [thinking_block, tool_use_block]
for block in response.content:
    print(f"Block type: {block.type}")
    if block.type == 'tool_use':
        print(f"Tool: {block.name}, Input: {block.input}")
